import React from 'react';
import type { PeriodCloseChecklistDto } from '../../services/kt/models';
import df from '../../styles/documentForm.module.css';

export interface PeriodCloseChecklistSectionProps {
  checklist: PeriodCloseChecklistDto | null;
  loading?: boolean;
  testIdPrefix: string;
}

export const PeriodCloseChecklistSection: React.FC<PeriodCloseChecklistSectionProps> = ({
  checklist,
  loading,
  testIdPrefix,
}) => {
  if (loading) {
    return (
      <div className={df.section} data-testid={`${testIdPrefix}-checklist-loading`}>
        <p style={{ margin: 0, fontSize: 13 }}>Đang kiểm tra điều kiện đóng sổ…</p>
      </div>
    );
  }

  if (!checklist) return null;

  return (
    <div className={df.section} data-testid={`${testIdPrefix}-checklist`}>
      <h2 className={df.sectionTitle}>Điều kiện đóng sổ kỳ {checklist.month}/{checklist.year}</h2>
      <p style={{ margin: '0 0 12px', fontSize: 13, lineHeight: 1.5 }}>
        Đóng sổ khóa kỳ sau khi hoàn tất xử lý cuối kỳ. Không sinh bút toán mới — chỉ cập nhật trạng thái kỳ kế toán.
      </p>
      <ul style={{ margin: 0, paddingLeft: 20, fontSize: 13, lineHeight: 1.6 }}>
        {checklist.items.map(item => (
          <li key={item.code} data-testid={`${testIdPrefix}-item-${item.code}`}>
            <span style={{ color: item.isOk ? 'var(--color-success, #198754)' : 'var(--color-danger, #dc3545)' }}>
              {item.isOk ? '✓' : '✗'}
            </span>
            {' '}
            <strong>{item.label}</strong>
            {item.detail ? ` — ${item.detail}` : ''}
          </li>
        ))}
      </ul>
      <p
        style={{
          margin: '12px 0 0',
          fontSize: 13,
          fontWeight: 600,
          color: checklist.canClose ? 'var(--color-success, #198754)' : 'var(--color-danger, #dc3545)',
        }}
        data-testid={`${testIdPrefix}-can-close`}
      >
        {checklist.canClose
          ? 'Đủ điều kiện đóng sổ.'
          : 'Chưa đủ điều kiện — hoàn tất các mục trên trước khi đóng sổ.'}
      </p>
    </div>
  );
};
